/**
 * Tests for the registry REST OpenAPI projection.
 *
 * `openapi/registry.openapi.json` is the ts-rest projection of
 * `src/contract/rest.ts` (generated by `scripts/generate-openapi.ts`). The
 * `git diff --exit-code` drift check in the `pillar-quality` workflow is the
 * canonical up-to-date guard; this suite locks in the structural invariants
 * (3.x version, info block, every operation has a summary + operationId) and
 * the shape of the served domains.
 */
import { readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import { describe, expect, it } from 'vitest';

interface Operation {
  summary?: string;
  operationId?: string;
}

interface OpenApiDocument {
  openapi: string;
  info: { title: string; version: string };
  paths: Record<string, Record<string, Operation>>;
  components?: { schemas?: Record<string, unknown> };
}

const here = dirname(fileURLToPath(import.meta.url));
const openapiPath = resolve(here, '..', '..', '..', 'openapi', 'registry.openapi.json');
const openapi = JSON.parse(readFileSync(openapiPath, 'utf8')) as OpenApiDocument;

describe('@pops/registry REST openapi projection', () => {
  it('declares an OpenAPI 3.x version', () => {
    expect(openapi.openapi).toMatch(/^3\./);
  });

  it('has an info block identifying the registry pillar contract', () => {
    expect(openapi.info.title).toBe('@pops/registry');
    expect(openapi.info.version).toMatch(/^\d+\.\d+\.\d+/);
  });

  it('exposes at least one path', () => {
    expect(Object.keys(openapi.paths).length).toBeGreaterThan(0);
  });

  it('every documented operation has a summary and operationId', () => {
    for (const [path, methods] of Object.entries(openapi.paths)) {
      for (const [method, operation] of Object.entries(methods)) {
        expect(operation.summary, `${method} ${path} missing summary`).toBeTruthy();
        expect(operation.operationId, `${method} ${path} missing operationId`).toBeTruthy();
      }
    }
  });

  it.each([
    ['GET', '/features/manifests', 'features.getManifests'],
    ['GET', '/features', 'features.list'],
    ['GET', '/features/{key}/enabled', 'features.isEnabled'],
    ['PUT', '/features/{key}/enabled', 'features.setEnabled'],
    ['PUT', '/features/{key}/preference', 'features.setUserPreference'],
    ['DELETE', '/features/{key}/preference', 'features.clearUserPreference'],
  ])('describes the %s %s endpoint with operationId %s', (method, path, operationId) => {
    const op = openapi.paths[path]?.[method.toLowerCase()];
    expect(op, `${method} ${path} should be documented`).toBeDefined();
    expect(op?.operationId).toBe(operationId);
  });

  it('serves no /ai-* paths (telemetry → ai pillar, categorizer cache → finance)', () => {
    expect(Object.keys(openapi.paths).some((p) => p.startsWith('/ai-'))).toBe(false);
  });

  it('documents only the served REST domains', () => {
    // Every documented path must live under one of these domain roots.
    const MIGRATED_DOMAIN_ROOTS = [
      '/users',
      '/shell',
      '/settings',
      '/service-accounts',
      '/features',
    ];
    const paths = Object.keys(openapi.paths);
    for (const p of paths) {
      expect(
        MIGRATED_DOMAIN_ROOTS.some((root) => p === root || p.startsWith(`${root}/`)),
        `${p} is not under a migrated domain root`
      ).toBe(true);
    }
    expect(paths.some((p) => p.startsWith('/core/'))).toBe(false);
  });

  it('exposes no entities surface or search slice (contacts is authoritative)', () => {
    const paths = Object.keys(openapi.paths);
    expect(paths.some((p) => p === '/entities' || p.startsWith('/entities/'))).toBe(false);
    expect(paths).not.toContain('/search');

    const operationIds = Object.values(openapi.paths).flatMap((methods) =>
      Object.values(methods).map((op) => op.operationId)
    );
    for (const removed of [
      'entities.list',
      'entities.get',
      'entities.create',
      'entities.update',
      'entities.delete',
      'search.search',
    ]) {
      expect(operationIds).not.toContain(removed);
    }
  });
});
